import ldap3

def search_user(username, server='ldap.example.com', port=389, base_dn='dc=example,dc=com'):
    try:
        connection = ldap3.Connection(server, user='cn=admin,'+base_dn, password='password')
        connection.bind()
        
        filter = '(uid={})'.format(username)
        attributes = ['*']
        response = connection.search(search_base=base_dn, search_filter=filter, search_scope=ldap3.SUBTREE, attributes=attributes)
        
        if response:
            for entry in connection.entries:
                return {'username': entry['uid'][0], 'email': entry['mail'][0]}
        else:
            return None
    except ldap3.core.exceptions.LDAPException as e:
        print('LDAP Exception: {}'.format(e))
        return None

# Example usage
print(search_user('john.doe'))